import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProjectFeed.css';

function ProjectFeed() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [skillFilter, setSkillFilter] = useState('');
  const [minBudget, setMinBudget] = useState('');
  const [maxBudget, setMaxBudget] = useState('');
  
  const navigate = useNavigate();

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://127.0.0.1:8000/api/projects/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProjects(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching projects:', error);
      setLoading(false);
    }
  };

  // Filter projects based on selected filters
  const getFilteredProjects = () => {
    return projects.filter(project => {
      // Skill filter
      if (skillFilter && project.skills_required) {
        if (!project.skills_required.toLowerCase().includes(skillFilter.toLowerCase())) {
          return false;
        }
      }
      
      // Min budget filter
      if (minBudget && parseFloat(project.budget_min) < parseFloat(minBudget)) {
        return false;
      }
      
      // Max budget filter
      if (maxBudget && parseFloat(project.budget_max) > parseFloat(maxBudget)) {
        return false;
      }
      
      return true;
    });
  };

  // Get unique skills for dropdown
  const getUniqueSkills = () => {
    const allSkills = [];
    projects.forEach(project => {
      if (project.skills_required) {
        project.skills_required.split(',').forEach(skill => {
          const trimmed = skill.trim();
          if (trimmed && !allSkills.includes(trimmed)) {
            allSkills.push(trimmed);
          }
        });
      }
    });
    return allSkills.sort();
  };

  const filteredProjects = getFilteredProjects();
  const uniqueSkills = getUniqueSkills();

  if (loading) return <div className="loading">Loading projects...</div>;

  return (
    <div className="project-feed">
      <h2>Available Projects</h2>
      
      {/* Filter Section - M2 Only */}
      <div className="filters">
        <select 
          value={skillFilter} 
          onChange={(e) => setSkillFilter(e.target.value)}
          className="filter-select"
        >
          <option value="">All Skills</option>
          {uniqueSkills.map(skill => (
            <option key={skill} value={skill}>{skill}</option>
          ))}
        </select>
        
        <input
          type="number"
          placeholder="Min Budget"
          value={minBudget}
          onChange={(e) => setMinBudget(e.target.value)}
          className="filter-input"
        />
        
        <input
          type="number"
          placeholder="Max Budget"
          value={maxBudget}
          onChange={(e) => setMaxBudget(e.target.value)}
          className="filter-input"
        />
      </div>

      <p className="results">{filteredProjects.length} projects found</p>

      {/* Projects Grid */}
      <div className="projects-grid">
        {filteredProjects.map(project => (
          <div key={project.id} className="project-card">
            <h3>{project.title}</h3>
            <p className="description">
              {project.description.length > 80 
                ? project.description.substring(0, 80) + '...' 
                : project.description}
            </p>
            
            <div className="details">
              <p><strong>💰 Budget:</strong> ₹{project.budget_min} - ₹{project.budget_max}</p>
              <p><strong>🛠️ Skills:</strong> {project.skills_required}</p>
              <p><strong>⏱️ Duration:</strong> {project.duration_days} days</p>
            </div>
            
            <button 
              className="view-btn"
              onClick={() => navigate(`/projects/${project.id}`)}
            >
              View Details
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ProjectFeed;
